async function checkAccess(): Promise<boolean> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/check-access', handlerParams({}))
        return res.data?.has_access ?? false
    } catch (e) {
        return false
    }
}

async function checkGroupAccess(): Promise<boolean> {
    try {
        const res = await axiosPostWithInt(BASE + 'daily-report/ai/check-group-access', handlerParams({}))
        return res.data?.has_access ?? false
    } catch (e) {
        return false
    }
}

/**
 * 发送消息，返回 fetch Response（SSE）
 * 调用方通过 response.body.getReader() 读取流
 */
async function askAi(params: AskParams, signal?: AbortSignal): Promise<Response> {
    const url = BASE + 'daily-report/ai/ask'
    // 复用现有请求头（签名等）——直接用 fetch，参照 axiosPostWithInt 的 headers
    const headers: Record<string, string> = {
        'Content-Type': 'application/json',
    }
    // 从 axios 实例拿通用 headers（token、签名等）
    const axiosDefaults = (axiosPostWithInt as any)?.defaults?.headers?.common ?? {}
    Object.assign(headers, axiosDefaults)

    return fetch(url, {
        method: 'POST',
        headers,
        credentials: 'include',
        signal,
        body: JSON.stringify(handlerParams({ ...params, response_format: 'stream' } as Record<string, any>)),
    })
}

