// ---- 聊天 ----
onKeydown(e: KeyboardEvent) {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault()
        this.sendMessage()
    }
}

async sendMessage() {
    const text = this.inputText.trim()
    if (!text || !this.currentRole || this.isStreaming) return

    // 有手动同步的 reportContext 且从未做过意图识别 → 直接问答（跳过意图识别）
    if (this.reportContext && !this.lastSlotResult) {
        await this.sendAskMessage(text)
    } else {
        // 走意图识别：LLM 判断是分析已有数据还是查询新数据
        await this.sendExtractSlots(text)
    }
}

/**
 * 意图识别流程：提取槽位，槽位齐全后自动拉日报数据再调 ask
 */
// 收集意图识别阶段待落库的消息
private pendingSlotMessages: { role: string; content: string }[] = []

/**
 * 将意图识别阶段的消息落库（创建或复用会话）
 */
private async flushSlotMessages() {
    if (!this.pendingSlotMessages.length || !this.currentRole) return
    const sessionId = await dailyReportAiApis.saveMessages({
        role_id: this.currentRole.id,
        session_id: this.currentSessionId,
        messages: this.pendingSlotMessages,
    })
    if (sessionId && !this.currentSessionId) {
        this.currentSessionId = sessionId
        await this.loadSessions()
    }
    this.pendingSlotMessages = []
}

private async sendExtractSlots(text: string) {
    this.messages.push({ role: 'user', content: text })
    this.pendingSlotMessages.push({ role: 'user', content: text })
    this.inputText = ''
    this.$nextTick(this.scrollToBottom)

    const assistantIdx = this.messages.length
    this.messages.push({ role: 'assistant', content: '' })
    this.isStreaming = true

    try {
        // 收集可用分组名和所有成员花名
        const availableGroups = this.groupOptions.map(g => g.label)
        const availableMembers = [...new Set(this.groupOptions.flatMap(g => g.value))].filter(Boolean)
        // 续查模式：传入上次的槽位结果
        const previousContext = this.lastSlotResult ? {
            member_type: this.lastSlotResult.member_type,
            members: this.lastSlotResult.members,
            period_start: this.lastSlotResult.period_start,
            period_end: this.lastSlotResult.period_end,
        } : undefined
        const hasExistingContext = this.messages.some(m => m.role === 'context')
        const result = await dailyReportAiApis.extractSlots({
            message: text,
            conversation_id: this.slotsConversationId || undefined,
            has_existing_context: hasExistingContext || undefined,
            available_groups: availableGroups,
            available_members: availableMembers,
            previous_context: previousContext,
        })

        if (!result) {
            this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
            this.pendingSlotMessages.push({ role: 'assistant', content: this.messages[assistantIdx].content })
            await this.flushSlotMessages()
            return
        }

        // 保存 conversation_id 用于多轮
        this.slotsConversationId = result.conversation_id

        // 意图为分析已有数据 → 直接走问答，不重新取数据
        if (result.intent === 'analyze') {
            // 移除占位的 assistant 消息，sendAskMessage 会重新创建
            this.messages.splice(assistantIdx, 1)
            this.isStreaming = false
            await this.flushSlotMessages()
            await this.sendAskMessage(text, true)
            return
        }

        if (!result.slots_complete) {
            // 槽位不完整，显示反问
            this.messages[assistantIdx].content = result.reply
            this.pendingSlotMessages.push({ role: 'assistant', content: result.reply })
            await this.flushSlotMessages()
            return
        }

        // 槽位完整，保存结果用于续查
        this.lastSlotResult = result
        // 回显意图识别结果
        const nicknames = this.resolveMembers(result)
        const memberLabel = result.member_type === 'group'
            ? `分组：${result.members.join('、')}`
            : `成员：${result.members.join('、')}`
        const countLabel = nicknames.length >= 10 ? `，共 ${nicknames.length} 人` : ''
        const periodLabel = `${result.period_start} ~ ${result.period_end}`
        const slotSummary = `查询对象：${memberLabel}${countLabel}\n时间范围：${periodLabel}${result.period_raw ? `（${result.period_raw}）` : ''}`
        this.messages[assistantIdx].content = slotSummary + '\n\n正在同步日报数据...'
        this.pendingSlotMessages.push({ role: 'assistant', content: slotSummary })
        this.$nextTick(this.scrollToBottom)

        if (!nicknames.length) {
            const errMsg = `未找到匹配的成员「${result.members.join('、')}」，请尝试使用花名或先手动同步数据。`
            this.messages[assistantIdx].content = errMsg
            this.pendingSlotMessages.push({ role: 'assistant', content: errMsg })
            await this.flushSlotMessages()
            return
        }

        const context = await this.fetchReportContext(nicknames, result.period_start, result.period_end)
        if (!context) {
            this.messages[assistantIdx].content = '该时间段内没有找到日报数据。'
            this.pendingSlotMessages.push({ role: 'assistant', content: '该时间段内没有找到日报数据。' })
            await this.flushSlotMessages()
            return
        }

        // 重置意图识别状态
        this.slotsConversationId = ''

        // 意图识别消息先落库（会创建 session）
        await this.flushSlotMessages()

        // 保留意图识别结果消息，走正常 ask 流程
        this.reportContext = context
        // 意图已由 extract-slots 处理，ask 只需分析同步好的日报数据
        await this.sendAskMessage('请根据以上日报数据进行分析')
    } catch (e: any) {
        this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
        this.pendingSlotMessages.push({ role: 'assistant', content: this.messages[assistantIdx].content })
        await this.flushSlotMessages()
    } finally {
        this.isStreaming = false
    }
}

/**
 * 根据槽位结果解析出 nicknames 列表
 */
private resolveMembers(result: ExtractSlotsResult): string[] {
    if (result.member_type === 'group') {
        // 匹配 groupOptions 的 label，展开为花名列表
        const matched = this.groupOptions.filter(g =>
            result.members.some(m => g.label.includes(m) || m.includes(g.label))
        )
        return [...new Set(matched.flatMap(g => g.value))].filter(Boolean)
    }
    // individual：LLM 返回的成员名必须在花名列表中匹配到，匹配不到则丢弃
    const allMembers = this.groupOptions.flatMap(g => g.value).filter(Boolean)
    return result.members
        .map(name => allMembers.find(m => m.includes(name) || name.includes(m)))
        .filter((n): n is string => !!n)
}

/**
 * 根据 nicknames + 日期范围拉取日报数据，返回聚合后的文本上下文
 */
private async fetchReportContext(nicknames: string[], startDate: string, endDate: string): Promise<string> {
    const days = moment(endDate).diff(moment(startDate), 'day') + 1
    const perPage = Math.max(200, days + 10)

    const results = await Promise.all(
        nicknames.map(nickname =>
            dailyReportApis.getOtherReportsAPI({
                start_date: startDate,
                end_date: endDate,
                nickname,
                per_page: perPage,
                page: 1,
                show_rest: 1,
                sys_site: this.sysSite,
            } as any)
        )
    )

    const dateMap: Record<string, string[]> = {}
    results.forEach((res, idx) => {
        if (!res) return
        const name = nicknames[idx].replace(/\[.+]/, '')
        ;(res.reports ?? []).forEach((item: any) => {
            const date = item.date ?? ''
            if (!dateMap[date]) dateMap[date] = []
            if (item.report) {
                dateMap[date].push(`${name}：\n${item.report.content ?? ''}`)
            } else if ([4, 5].includes(item.type_id)) {
                dateMap[date].push(`${name}：休息日`)
            } else {
                dateMap[date].push(`${name}：未提交`)
            }
        })
    })

    const sortedDates = Object.keys(dateMap).sort((a, b) => b.localeCompare(a))
    return sortedDates
        .map(date => `【${date}】\n${dateMap[date].join('\n\n')}`)
        .join('\n\n---\n\n')
}

