    // 切换会话时中断正在进行的流式请求
    if (this.streamAbort) {
        this.streamAbort.abort()
        this.streamAbort = null
    }
    this.isStreaming = false
    this.currentSessionId = sessionId
    // 切换会话时重置意图识别状态，防止残留上一次的槽位结果
    this.slotsConversationId = ''
    this.lastSlotResult = null
    this.reportContext = ''
    this.pendingSlotMessages = []
    this.messagesLoading = true
    try {
        const msgs = await dailyReportAiApis.getSessionMessages(sessionId)
        this.messages = msgs.map(m => ({
            role: m.role,
            content: m.content,
            _id: m.id,
            _truncated: m.is_truncated || false,
            _fullLength: m.full_length || 0,
        }))
        this.$nextTick(() => {
            this.scrollToBottom()
            // markdown 渲染后高度可能变化，再滚一次
            setTimeout(() => this.scrollToBottom(), 100)
        })
    } finally {
        this.messagesLoading = false
    }
}

