    const response = await dailyReportAiApis.askAi({
        role_id: this.currentRole!.id,
        session_id: this.currentSessionId,
        message: text,
        report_context: compressedContext,
        report_context_raw: contextToSend ? await this.compressContext(contextToSend) : undefined,
        history,
    }, this.streamAbort.signal)

    const reader = response.body!.getReader()
    const decoder = new TextDecoder()
    let buffer = ''

    while (true) {
        const { done, value } = await reader.read()
        if (done) break
        buffer += decoder.decode(value, { stream: true })
        const lines = buffer.split('\n')
        buffer = lines.pop() ?? ''

        for (const line of lines) {
            if (!line.startsWith('data: ')) continue
            try {
                const parsed = JSON.parse(line.slice(6))
                if (parsed.error_code !== 0) {
                    this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
                    break
                }
                const data = parsed.data
                if (data.type === 'session_id') {
                    if (!this.currentSessionId) {
                        this.currentSessionId = Number(data.session_id)
                        await this.loadSessions()
                    }
                } else if (data.type === 'chat' && data.content) {
                    this.messages[assistantIdx].content += data.content
                    this.$nextTick(this.scrollToBottom)
                }
            } catch (_) {}
        }
