 * 正常问答流程：带 reportContext 调 askAi（SSE 流式）
 */
private async sendAskMessage(text: string, skipUserPush = false) {
    const contextToSend = this.reportContext
    // 记录本轮消息插入起点，取消时用于回退
    const msgStartIdx = this.messages.length
    if (contextToSend) {
        const contextLimit = 5000
        const isTruncated = contextToSend.length > contextLimit
        this.messages.push({
            role: 'context',
            content: isTruncated ? contextToSend.slice(0, contextLimit) : contextToSend,
            _truncated: isTruncated,
            _fullLength: contextToSend.length,
            _fullContent: isTruncated ? contextToSend : undefined,
        })
        this.reportContext = ''
    }
    if (!skipUserPush) {
        this.messages.push({ role: 'user', content: text })
        this.inputText = ''
    }
    this.$nextTick(this.scrollToBottom)

    const assistantIdx = this.messages.length
    this.messages.push({ role: 'assistant', content: '' })
    this.isStreaming = true

    this.streamAbort = new AbortController()
    try {
        const history = this.messages.slice(0, -2).filter(m => m.role !== 'context' && !!m.content).slice(-10) as { role: 'user' | 'assistant'; content: string }[]
        const processedContext = contextToSend ? compressDailyContext(contextToSend) : ''
        if (processedContext) {
            console.log('[AiChat] 压缩前上下文:\n', processedContext)
        }
        const compressedContext = processedContext ? await this.compressContext(processedContext) : ''
        // 检查累积上下文原始字符数是否可能超限（阈值 150 万字符）
        const newContextChars = contextToSend ? contextToSend.length : 0
        const contextCharLimit = 1_500_000
        if (this.accumulatedContextChars + newContextChars > contextCharLimit) {
            try {
                await this.$confirm(
                    this.$t('aiChat.contextOverLimit') as string,
                    this.$t('aiChat.confirmTitle') as string,
                    {
                        confirmButtonText: this.$t('aiChat.contextOverLimitContinue') as string,
                        cancelButtonText: this.$t('aiChat.contextOverLimitNewSession') as string,
                        type: 'warning',
                    },
                )
                // 用户选择继续发送，不拦截
            } catch {
                // 用户选择新建会话：回退本轮添加的所有消息
                this.messages.splice(msgStartIdx)
                this.isStreaming = false
                this.streamAbort = null
                this.newSession()
                return
            }
        }
        const response = await dailyReportAiApis.askAi({
            role_id: this.currentRole!.id,
            session_id: this.currentSessionId,
            message: text,
            report_context: compressedContext,
            report_context_raw: contextToSend ? await this.compressContext(contextToSend) : undefined,
            history,
        }, this.streamAbort.signal)

        const reader = response.body!.getReader()

