onKeydown(e: KeyboardEvent) {
    if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault()
        this.sendMessage()
    }
}

async sendMessage() {
    const text = this.inputText.trim()
    if (!text || !this.currentRole || this.isStreaming) return

    // 有手动同步的 reportContext 且从未做过意图识别 → 直接问答（跳过意图识别）
    if (this.reportContext && !this.lastSlotResult) {
        await this.sendAskMessage(text)
    } else {
        // 走意图识别：LLM 判断是分析已有数据还是查询新数据
        await this.sendExtractSlots(text)

